  ('police-b20a8cf8-moex-00014', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '關於教育領域之宗教中立原則，下列敘述何者錯誤？', '["主管教育行政機關不得強迫教師參加特定宗教團體舉辦之宗教活動", "主管教育行政機關不得強迫學生參加特定宗教團體舉辦之宗教活動", "主管教育行政機關不得強迫學校行政人員參加特定宗教團體舉辦之宗教活動", "公立大學得要求學生在畢業前須參加至少一次宗教活動，否則不具畢業資格"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00015', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '依司法院大法官解釋，關於憲法結社自由，下列敘述何者錯誤？', '["人民團體法亦為我國人民結社之法律依據", "結社自由之保障範圍不包含組織內部之安排，主管機關依人民團體法得予以介入", "大法官解釋曾宣告人民團體法限制人民團體不得主張共產主義之規定違憲", "結社自由包含社團組成之發起自由、名稱使用及更改名稱之自由"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00016', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '依司法院釋字第790號解釋，有關毒品危害防制條例第12條第2項所定栽種大麻罪之法定 刑，下列敘述何者錯誤？', '["情輕法重，違反憲法罪刑相當原則", "立法者就何種犯罪及何種情狀得否減輕其刑，屬立法形成自由之範疇", "5年以上最低法定刑部分，對人身自由之限制，違反比例原則", "毒品危害防制條例第17條第2項減輕其刑規定，未包括犯同條例第12條第2項栽種大麻 之罪，違反憲法第7條保障平等權之意旨"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00017', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '依司法院釋字第400號解釋，既成道路成立公用地役關係之三個要件，不包括下列何者？', '["須為不特定之公眾通行所必要，而非僅為通行之便利或省時", "於公眾通行之初，土地所有權人並無阻止之情事", "須經歷之年代久遠而未曾中斷", "須有建築法或民法等之相關規定作為依據"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00018', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '土地稅法第39條第2項關於免徵土地增值稅規定，僅就依都市計畫法指定之公共設施保留 地，免徵其土地增值稅；至非都市土地經編定為交通用地，且依法核定為公共設施用地者， 則不予免徵土地增值稅。依司法院釋字第779號解釋，於此範圍內，係違反下列何項原則？', '["比例原則", "平等原則", "法律明確性原則", "依法行政原則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00019', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '關於服兵役，下列敘述何者正確？', '["為憲法所未明文列舉之義務", "若需降低服兵役之年齡，應修改憲法", "若需納入女性為服兵役義務主體，應修改憲法", "人民如何履行服兵役之義務，應以法律定之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00020', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '人民受教育之權利分為「受國民教育之權利」及「受國民教育以外教育之權利」，依司法院 大法官解釋之意旨，下列敘述何者正確？', '["憲法明定，受國民教育與受國民教育以外教育，均為人民之權利與義務", "分別受憲法不同條文所保障", "國家對提供國民教育與國民教育以外之教育，均負有義務", "二者皆不得訂定特定之入學資格，排除資格不符之考生入學就讀 51250、51350"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00021', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '依相關司法院大法官解釋，有關契約自由，下列敘述何者錯誤？', '["跨國婚姻媒合不得期約報酬，係對契約自由之限制", "契約自由為司法院大法官解釋肯認之非明文憲法權利", "契約自由為個人自主發展與實現自我之重要機制", "公法上契約與私法上契約享有同樣的契約自由"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00022', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '有關健康權之敘述，下列何者錯誤？', '["為司法院大法官解釋肯認之非明文憲法權利", "有關藥害救濟制度之設置，屬社會福利措施，尚無涉憲法保障之健康權", "有關消防人員勤務休息規定，涉及健康權之保障", "萊克多巴胺容許標準之訂定，涉及國家對於人民健康權之保障"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00023', 'police-b20a8cf8', 'police-b20a8cf8-moex-114-15a7b19c', 'sub-police-b20a8cf8-01', NULL, 'single_choice', '依司法院釋字第803號解釋，原住民可基於生命權、身體權、原住民狩獵文化權，主張享有 持安全獵槍進行狩獵的自由。下列何者最適合描述此處生命權、身體權、原住民狩獵文化權 的關係？', '["基本權衝突", "基本權競合", "基本權涵攝", "基本權位階"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:21+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "503", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
